## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGlateximage.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "Pd.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
Context()->operators->remove("U");
@orig_vars = random_subset(2, 'a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'Z');
@vars = (@orig_vars, @orig_vars);
@vars = (@vars)[NchooseK(4,4)];
Context()->variables->are();
for my $i (1,2) {
  Context()->variables->add($orig_vars[$i-1] => 'Real');
}

@fracs = ();
for my $j (2..10) {
  for my $i (1..10) {
    push(@fracs, Fraction($i,$j));
  }
}

@coefs = num_sort((@fracs)[NchooseK(90,4)]);
@terms = ();
for my $i (1..4) {
  push(@terms, Formula("$coefs[$i-1]*$vars[$i-1]")->reduce);
}
$sum = Formula(join('+', @terms))->reduce;

%combinedcoefs = ();
$combinedcoefs{$orig_vars[0]} = Fraction($sum->eval($orig_vars[0] => 1, $orig_vars[1] => 0));
$combinedcoefs{$orig_vars[1]} = Fraction($sum->eval($orig_vars[0] => 0, $orig_vars[1] => 1));
$ans = Formula("$combinedcoefs{$orig_vars[0]} $orig_vars[0] + $combinedcoefs{$orig_vars[1]} $orig_vars[1]")->reduce;

Context("Form");
Context()->operators->remove("U");
Context()->variables->are();
for my $i (1,2) {
  Context()->variables->add($orig_vars[$i-1] => 'Real');
}

$ans = Formula("$ans");

$polygon = list_random(
  [[0,3,3.5,2], [0,0,2,2.5], [2,1,0,3]],
  [[0,4,3.5,1], [0,0,2,2.5], [3,0,1,2]],
  [[0,3,3.5,2], [0,-1,1,2.5], [3,1,0,2]],
  [[0,3,3.5,2], [0,-1,2,2.5], [2,1,0,3]],
  [[0,3,3.5,1], [0,-1,2,2], [3,2,1,0]],
);

@x = @{$polygon->[0]};
@y = @{$polygon->[1]};
@termsTeX = map{$terms[$_]->TeX} (@{$polygon->[2]});

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \draw[fill=wood] ($x[0],$y[0])
  -- node[pos=0.5,below]{\($termsTeX[0]\)} ($x[1],$y[1])
  -- node[pos=0.5,right]{\($termsTeX[1]\)} ($x[2],$y[2])
  -- node[pos=0.5,above]{\($termsTeX[2]\)} ($x[3],$y[3])
  -- node[pos=0.5,left]{\($termsTeX[3]\)} cycle;   
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
Write a simplified expression for the perimeter of the given shape (which is not drawn to scale).

>> [@image(insertGraph($image_1), width=>564, alt=>qq"a quadrilateral whose sides are labeled $terms[0], $terms[1], $terms[2], and $terms[3].")@]*  <<

[_]{$ans}{20}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
The perimeter is the result from adding the four sides together: [`[$termsTeX[0]] + [$termsTeX[1]] + [$termsTeX[2]] + [$termsTeX[3]]\text{.}`] There are two [`[$vars[0]]`]-terms and two [`[$vars[1]]`]-terms. We combine each pair of like terms and the perimeter is [`[$ans]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
